import{_ as e,o as a,c as r,S as t}from"./chunks/framework.233e4693.js";const o="/auto-crudx/assets/get-start-1.418f4a55.mp4",s="/auto-crudx/assets/get-start-2.b71fc00a.mp4",n="/auto-crudx/assets/get-start-3.22afe944.mp4",_=JSON.parse('{"title":"Comenzar","description":"","frontmatter":{},"headers":[],"relativePath":"get-start.md","filePath":"get-start.md"}'),i={name:"get-start.md"},l=t('<h1 id="comenzar" tabindex="-1">Comenzar <a class="header-anchor" href="#comenzar" aria-label="Permalink to &quot;Comenzar&quot;">​</a></h1><h2 id="¿-que-es-un-crud" tabindex="-1">¿ Qué es un CRUD ? <a class="header-anchor" href="#¿-que-es-un-crud" aria-label="Permalink to &quot;¿ Qué es un CRUD ?&quot;">​</a></h2><p>En informática, <a href="https://en.wikipedia.org/wiki/Create,_read,_update_and_delete" target="_blank" rel="noreferrer">CRUD</a> es el acrónimo de <em>&quot;Crear&quot;</em>, <em>&quot;Leer&quot;</em>, <em>&quot;Actualizar&quot;</em> y <em>&quot;Borrar&quot;</em>, (del original en inglés, <em>Create, Read, Update and Delete</em>), que se usa para referirse a las funciones básicas en bases de datos o la capa de persistencia en un software.</p><h2 id="¿-por-que-auto-crudx" tabindex="-1">¿ Por qué Auto-CRUDx ? <a class="header-anchor" href="#¿-por-que-auto-crudx" aria-label="Permalink to &quot;¿ Por qué Auto-CRUDx ?&quot;">​</a></h2><p>Las funciones básicas en bases de datos o la capa de persistencia en un software son tareas repetitivas que se hacen regularmente cuando de desarrollo de software se trata. Por lo que, una vez definida una estructura estandar, para los típicos CRUDs, es útil una herramienta que los genere automáticamente.</p><h2 id="¿-que-es-auto-crudx" tabindex="-1">¿ Qué es Auto-CRUDx ? <a class="header-anchor" href="#¿-que-es-auto-crudx" aria-label="Permalink to &quot;¿ Qué es Auto-CRUDx ?&quot;">​</a></h2><p><a href="https://github.com/ecanquiz/node-auto-crudx" target="_blank" rel="noreferrer">Auto-CRUDx</a> es una herramienta que ayuda a crear su propio Generador de CRUDs Automático según su propia pila de desarrollp y arquitectura particular.</p><div class="tip custom-block"><p class="custom-block-title">Importante</p><p><strong>Auto-CRUDx</strong> brinda las herramientas para ayudarlo a crear su propio Generador de CRUDs Automático (según su propia pila de desarrollp y arquitectura particular). Por lo tanto, usted mismo debe diseñar sus plantillas según su criterio.</p></div><h2 id="ejemplos" tabindex="-1">Ejemplos <a class="header-anchor" href="#ejemplos" aria-label="Permalink to &quot;Ejemplos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Advertencia</p><p><em><strong>Auto-CRUDx</strong></em> no genera <em>Scaffold</em>. Por lo tanto, no genera <em>Layout</em>, <em>Sign In</em>, <em>Sign Up</em>, <em>Password Recovery</em>, etc.</p></div><p>Los siguientes ejemplos de CRUDs fueron creados a travéz de la herramienta <em><strong>Auto-CRUDx</strong></em>, la cual fue desarrollada con <a href="https://laravel.com/" target="_blank" rel="noreferrer">Laravel</a> y <a href="https://vuejs.org/" target="_blank" rel="noreferrer">Vue</a>.</p><div class="tip custom-block"><p class="custom-block-title">Información</p><p>Usted puede consultar el código generado, tanto del <a href="https://github.com/CaribesTIC/laravuel-api/tree/main/Modules/Meeting" target="_blank" rel="noreferrer">Backend</a> como del <a href="https://github.com/CaribesTIC/laravuel-spa/tree/main/src/modules/Meeting" target="_blank" rel="noreferrer">Frontend</a>, de los siguientes ejemplos.</p></div><h2 id="_1°-crud-basico" tabindex="-1">1° CRUD Básico <a class="header-anchor" href="#_1°-crud-basico" aria-label="Permalink to &quot;1° CRUD Básico&quot;">​</a></h2><video controls><source src="'+o+'"></video><h2 id="_2°-crud-intermedio" tabindex="-1">2° CRUD Intermedio <a class="header-anchor" href="#_2°-crud-intermedio" aria-label="Permalink to &quot;2° CRUD Intermedio&quot;">​</a></h2><video controls><source src="'+s+'"></video><h2 id="_3°-crud-avanzado" tabindex="-1">3° CRUD Avanzado <a class="header-anchor" href="#_3°-crud-avanzado" aria-label="Permalink to &quot;3° CRUD Avanzado&quot;">​</a></h2><video controls><source src="'+n+'"></video><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><p>Auto-CRUDx está desarrollada en <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node</a>, por lo que es importante tener conocimientos mínimos del mismo y tenerlo instalado en su maquina.</p><p>Además, usa como dependencia las Plantillas de JavaScript Integradas <a href="https://www.npmjs.com/package/ejs" target="_blank" rel="noreferrer">EJS</a>. Por lo que también es fundamental leer la respectiva <a href="https://ejs.co/" target="_blank" rel="noreferrer">documentación</a>.</p><p>La actual versión del <strong>Auto-CRUx</strong>, solo se alimenta de la información proveniente del diseño de sus tablas creadas en su bases de datos <a href="https://www.postgresql.org/" target="_blank" rel="noreferrer">PostgreSQL</a>. Por lo que debe tener previamente instalado PostgreSQL en su máquina, así como también haber construido sus correspondientes tablas en dicha base de datos.</p>',22),u=[l];function d(c,m,p,h,b,g){return a(),r("div",null,u)}const q=e(i,[["render",d]]);export{_ as __pageData,q as default};
